519	        }
520	
521	        if (maxCount === -1) {
522	            this.m_concurrentLimits.delete(audioKey);
523	        } else {
524	            this.m_concurrentLimits.set(audioKey, maxCount);
525	        }
526	    }
527	
528	    /**
529	     * 設定預設並發限制
530	     * @description 設定所有音效的預設並發限制，對於沒有特別設定的音效生效
531	     * @param maxCount 預設最大並發數量，設為 -1 表示無限制
532	     * @example
533	     * ```typescript
534	     * // 設定所有音效預設最多同時播放 5 個
535	     * AudioManager.SetDefaultConcurrentLimit(5);
536	     *
537	     * // 移除預設限制
538	     * AudioManager.SetDefaultConcurrentLimit(-1);
539	     * ```
540	     */
541	    static SetDefaultConcurrentLimit(maxCount: number): void {
542	        if (maxCount <= 0 && maxCount !== -1) {
