568	     * @description 取得指定音效當前正在播放的實例數量
569	     * @param audioKey 音效鍵名
570	     * @returns 當前播放數量
571	     * @example
572	     * ```typescript
573	     * const currentCount = AudioManager.GetCurrentPlayingCount("skill_explosion");
574	     * console.log(`技能爆炸音效當前播放數量: ${currentCount}`);
575	     * ```
576	     */
577	    static GetCurrentPlayingCount(audioKey: string): number {
578	        const instances = this.m_playingInstances.get(audioKey);
579	        return instances ? instances.size : 0;
580	    }
581	
582	    /**
583	     * 查詢音效並發限制
584	     * @description 取得指定音效的並發限制設定
585	     * @param audioKey 音效鍵名
586	     * @returns 並發限制數量，-1 表示無限制
587	     * @example
588	     * ```typescript
589	     * const limit = AudioManager.GetConcurrentLimit("skill_explosion");
590	     * if (limit === -1) {
591	     *     console.log("技能爆炸音效無並發限制");
592	     * } else {
593	     *     console.log(`技能爆炸音效並發限制: ${limit}`);
594	     * }
595	     * ```
596	     */
597	    static GetConcurrentLimit(audioKey: string): number {
598	        return this.m_concurrentLimits.get(audioKey) || this.m_defaultConcurrentLimit;
599	    }
600	
601	    /**
602	     * 停止指定音效的所有實例
603	     * @description 停止指定音效的所有正在播放的實例
604	     * @param audioKey 音效鍵名
605	     * @returns 停止的音效數量
606	     * @example
607	     * ```typescript
608	     * const stoppedCount = AudioManager.StopAllInstances("skill_explosion");
609	     * console.log(`已停止 ${stoppedCount} 個技能爆炸音效`);
610	     * ```
611	     */
612	    static StopAllInstances(audioKey: string): number {
613	        const instances = this.m_playingInstances.get(audioKey);
614	        if (!instances || instances.size === 0) {
615	            return 0;
616	        }
617	
618	        let stoppedCount = 0;
619	        for (const audioId of instances) {
620	            soundAudioManager.Stop(audioId);
621	            this.m_instanceMetadata.delete(audioId);
622	            stoppedCount++;
623	        }
624	
625	        instances.clear();
626	        return stoppedCount;
627	    }
628	
629	    /**
