631	     * @description 清除所有音效的並發限制設定和播放記錄
632	     * @example
633	     * ```typescript
634	     * AudioManager.ClearAllConcurrentLimits();
635	     * ```
636	     */
637	    static ClearAllConcurrentLimits(): void {
638	        this.m_concurrentLimits.clear();
639	        this.m_playingInstances.clear();
640	        this.m_instanceMetadata.clear();
641	        this.m_defaultConcurrentLimit = -1;
642	        this.m_overflowStrategy = ConcurrentOverflowStrategy.IGNORE;
643	    }
644	
645	    // =================================================================
646	    // 內部方法 (Private Methods)
647	    // =================================================================
