649	    /**
650	     * 檢查並發限制
651	     * @description 檢查指定音效是否可以播放，如果超過限制則根據策略處理
652	     * @param audioKey 音效鍵名
653	     * @returns 是否可以播放
654	     */
655	    private static CheckConcurrentLimit(audioKey: string): boolean {
656	        const limit = this.GetConcurrentLimit(audioKey);
657	        if (limit === -1) {
658	            return true; // 無限制
659	        }
660	
661	        const currentCount = this.GetCurrentPlayingCount(audioKey);
662	        if (currentCount < limit) {
663	            return true; // 未超過限制
664	        }
665	
666	        // 超過限制，根據策略處理
667	        if (this.m_overflowStrategy === ConcurrentOverflowStrategy.REPLACE_OLDEST) {
668	            this.StopOldestInstance(audioKey);
669	            return true;
670	        }
671	
672	        return false; // 忽略新請求
673	    }
674	
675	    /**
676	     * 停止最舊的音效實例
677	     * @description 停止指定音效的最舊播放實例
678	     * @param audioKey 音效鍵名
679	     */
680	    private static StopOldestInstance(audioKey: string): void {
681	        const instances = this.m_playingInstances.get(audioKey);
682	        if (!instances || instances.size === 0) {
683	            return;
684	        }
685	
686	        let oldestId = -1;
687	        let oldestTime = Number.MAX_VALUE;
688	
689	        // 找出最舊的實例
690	        for (const audioId of instances) {
691	            const metadata = this.m_instanceMetadata.get(audioId);
692	            if (metadata && metadata.startTime < oldestTime) {
693	                oldestTime = metadata.startTime;
694	                oldestId = audioId;
695	            }
696	        }
697	
698	        if (oldestId !== -1) {
699	            soundAudioManager.Stop(oldestId);
700	            this.RemovePlayingInstance(audioKey, oldestId);
701	        }
702	    }
703	
704	    /**
705	     * 添加播放實例
706	     * @description 將新的音效實例添加到追蹤列表
707	     * @param audioKey 音效鍵名
708	     * @param audioId 音效 ID
709	     */
710	    private static AddPlayingInstance(audioKey: string, audioId: number): void {
711	        if (!this.m_playingInstances.has(audioKey)) {
712	            this.m_playingInstances.set(audioKey, new Set());
713	        }
714	        this.m_playingInstances.get(audioKey)!.add(audioId);
715	
716	        // 記錄元數據
717	        this.m_instanceMetadata.set(audioId, {
718	            audioKey: audioKey,
719	            startTime: Date.now()
720	        });
721	    }
722	
723	    /**
724	     * 移除播放實例
725	     * @description 從追蹤列表中移除指定的音效實例
726	     * @param audioKey 音效鍵名
727	     * @param audioId 音效 ID
728	     */
729	    private static RemovePlayingInstance(audioKey: string, audioId: number): void {
730	        const instances = this.m_playingInstances.get(audioKey);
731	        if (instances) {
732	            instances.delete(audioId);
733	            if (instances.size === 0) {
734	                this.m_playingInstances.delete(audioKey);
735	            }
736	        }
737	
738	        this.m_instanceMetadata.delete(audioId);
739	    }
740	}
